#include<bits/stdc++.h>
using namespace std;
long long n,m;
struct matrix
{
    long long a[4][4],r,c;
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix ans;
        ans.r=a.r;
        ans.c=b.c;
        for(long long i=1;i<=a.r;i++)
        {
            for(long long j=1;j<=b.c;j++)
            {
                for(long long k=1;k<=a.c;k++)
                {
                    ans.a[i][j]+=1ll*(a.a[i][k]%m)*(b.a[k][j]%m)%m;
                    ans.a[i][j]%=m;
                }
            }
        }
        return ans;
    }
}base,ans,base1;
void fastpow(unsigned long long y)
{
    while(y)
    {
        if(y%2==1)
        {
            ans=base*ans;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    ans.r=3;
    ans.c=1;
    ans.a[2][1]=ans.a[3][1]=1;
    base1.r=base1.c=3;
    base1.a[1][2]=base1.a[2][2]=base1.a[2][3]=base1.a[3][3]=1;
    for(unsigned long long k=10;;k*=10)
    {
        base=base1;
        base.a[1][1]=k%m;
        fastpow(k<=n?(k/10*9):(n-k/10+1));
        if(k>n)
        {
            break;
        }
    }
    printf("%lld",ans.a[1][1]);
    return 0;
}
